/**
 * Returns the entities (properties / businesses) where BOTH the
authenticated viewer and the target user have an approved
`entity_members` row. Powers the "Shared: …" line in
PublicProfileModal so the viewer can see at a glance which
workspaces tie them to the person they're looking at. Empty
list when the two users share no approved memberships, or
when the viewer is looking at their own profile.

 * @summary Entities both the viewer and the target user are approved members of
 */
export const ListSharedEntitiesWithUserParams = zod.object({
  userId: zod.coerce.string(),
});

export const ListSharedEntitiesWithUserResponse = zod.object({
  entities: zod.array(
    zod.object({
      id: zod.number(),
      name: zod.string(),
      kind: zod.enum([
        "business",
        "residential_property",
        "commercial_property",
      ]),
    }),
  ),
});

