/**
 * Returns up to 100 of the most recently created business invites the
signed-in user has sent, newest first. Powers the "My invites" screen
so the sender can see status (pending/sent/failed/accepted) and
retrigger failed sends.

 * @summary List the current user's recent business invites
 */
export const ListMyBusinessInvitesResponse = zod.object({
  invites: zod.array(
    zod.object({
      id: zod.number(),
      email: zod.string(),
      businessName: zod.string().nullish(),
      status: zod.enum(["pending", "sent", "failed", "accepted"]),
      createdAt: zod.coerce.date(),
      sentAt: zod.coerce.date().nullish(),
      acceptedAt: zod.coerce.date().nullish(),
      sendError: zod.string().nullish(),
    }),
  ),
});

/**
 * Records a pending business invite from the current user and sends the
invite email directly to the recipient. The Find > Businesses invite
modal calls this endpoint instead of opening the device's mail app.

 * @summary Create a business invite record and email the recipient
 */
export const SendBusinessInviteBody = zod.object({
  email: zod
    .string()
    .email()
    .describe("Email address of the recipient business contact."),
  businessName: zod
    .string()
    .nullish()
    .describe("Optional business name to personalize the invite copy."),
});

export const SendBusinessInviteResponse = zod.object({
  id: zod.number(),
  email: zod.string(),
  businessName: zod.string().nullish(),
  status: zod.enum(["pending", "sent", "failed", "accepted"]),
  sentAt: zod.coerce.date().nullish(),
});

/**
 * Public endpoint used by the invite landing page so the recipient can
see who invited them (and what business name was used) before signing
in. Does not mutate state.

 * @summary Look up a business invite by its token
 */
export const GetBusinessInviteParams = zod.object({
  token: zod.coerce.string(),
});

export const GetBusinessInviteResponse = zod.object({
  id: zod.number(),
  email: zod.string(),
  businessName: zod.string().nullish(),
  status: zod.enum(["pending", "sent", "failed", "accepted"]),
  acceptedAt: zod.coerce.date().nullish(),
  inviter: zod
    .object({
      clerkId: zod.string(),
      name: zod.string(),
      username: zod.string(),
    })
    .nullish(),
});

/**
 * Marks the invite identified by `token` as accepted (sets `acceptedAt`)
and creates a two-way `collaborator` connection between the inviter
and the current authenticated user so the invite shows up in both
people's relationships.

 * @summary Accept a business invite as the signed-in recipient
 */
export const AcceptBusinessInviteBody = zod.object({
  token: zod.string().describe("Single-use invite token from the email link."),
});

export const AcceptBusinessInviteResponse = zod.object({
  id: zod.number(),
  email: zod.string(),
  businessName: zod.string().nullish(),
  status: zod.enum(["pending", "sent", "failed", "accepted"]),
  acceptedAt: zod.coerce.date().nullish(),
  inviter: zod.object({
    clerkId: zod.string(),
    name: zod.string(),
    username: zod.string(),
  }),
});

